-- Create "user_platform_quota" table
CREATE TABLE "user_platform_quota" (
  "id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY,
  "created_at" timestamptz NOT NULL,
  "updated_at" timestamptz NOT NULL,
  "user_id" bigint NOT NULL,
  "platform" character varying NOT NULL,
  "daily_limit" character varying NULL,
  "weekly_limit" character varying NULL,
  "monthly_limit" character varying NULL,
  "currency" character varying NOT NULL DEFAULT 'USD',
  "enabled" boolean NOT NULL DEFAULT true,
  PRIMARY KEY ("id")
);
-- Create index "userplatformquota_user_id_enabled" to table: "user_platform_quota"
CREATE INDEX "userplatformquota_user_id_enabled" ON "user_platform_quota" ("user_id", "enabled");
-- Create index "userplatformquota_user_id_platform" to table: "user_platform_quota"
CREATE UNIQUE INDEX "userplatformquota_user_id_platform" ON "user_platform_quota" ("user_id", "platform");
